- 'Severe allergies' refer to allergic reactions that are life-threatening or cause significant health complications.

sql:
SELECT p.patient_id
FROM patients p
WHERE EXISTS (
    SELECT 1 FROM allergies a WHERE a.patient_id = p.patient_id
) AND EXISTS (
    SELECT 1 FROM lab_results lr WHERE lr.patient_id = p.patient_id
) AND EXISTS (
    SELECT 1 FROM medications m WHERE m.patient_id = p.patient_id
)
ORDER BY p.patient_id
LIMIT 1;
